const DEBUG = false;
const DEBUG_PREFIX = '[HR3472]';

function debug(errorText) {
    if (DEBUG) {
        console.log(`${DEBUG_PREFIX} ${errorText}`);
    }
}

function additionalInit() {
    debug('Additional Init started');
    initLetterDate();
    initLetterToggle();
    createIdListeners();
    initPaymentAmountField(); // amount of payment refine to 2 decimal
    debug('Additional Init ended');
}

function updateNonMoustache() { }

// ============= ELEMENTS IDS =================
const ELEMENT_IDS = {
    TOGGLE_BUTTON: 'show-letter-a37ad442-dabd-45dc-887d-157dca5b1135',
    FORM_CONTAINER: 'form-b7a7577c-23da-4997-a8da-98060af183a7',
    LETTER_CONTAINER: 'letter-content-961f5084-585e-4564-ae23-f18eebd455ff',
    SR_NUMBER: 'service-request-b9d4cb06-5bef-4975-aa62-712615d90f3e' /* Service Request (Text Input) */,
    CASE_NUMBER: 'case-b1e86eab-8042-4ec5-906d-9a140ce540c6' /* Case (Text Input) */,
    MIS_NUMBER: 'mis-c6cfdd7e-3fd9-451b-9369-c733eb3098bb' /* MIS (Text Input) */,
};

// ============== FORM FIELD MAPPING ==============
let formElementMapping = {
    payment_amount: 'payment-amount-ea02d788-f77c-4938-91de-a53698712b76',
    letter_date: 'letter-date-e999c869-7738-47a9-b3ca-84e2f0bcf98c',
    client_fullname: 'client-full-name-7666c5bf-e504-4141-b8bd-28e3917797c9',
    client_street_address: 'street-address-360bb2ee-52f6-4caf-ad99-89f065be068e',
    client_city: 'city-50474087-ab03-4a53-9eb9-d00f4e2b20a9',
    client_postal_code: 'postal-code-868c30ba-9fb1-41dc-b771-b69d4601a99c',
    client_province: 'province-76e57e7c-7666-4854-939c-d28002eb51a6',
    case_number: '#literal:',
    sr_number: '#literal:',
    mis_number: '#literal:'
};

// -------- CONSTANTS ----- //
const UI_STRINGS = {
    SHOW_LETTER: 'Show Letter',
    SHOW_FORM: 'Show Form'
}

// amount of payment helper
function initPaymentAmountField() {
    const id = formElementMapping.payment_amount;
    const input = document.getElementById(id);
    if (!input) return;

    // Limit characters while typing
    input.addEventListener('input', () => {
        let v = input.value;

        // Allow only digits + 1 dot
        v = v.replace(/[^\d.]/g, '');

        const dotIndex = v.indexOf('.');
        if (dotIndex !== -1) {
            // Remove additional dots
            v = v.slice(0, dotIndex + 1) + v.slice(dotIndex + 1).replace(/\./g, '');
        }

        // Limit to 2 decimals
        const parts = v.split('.');
        if (parts[1]?.length > 2) {
            v = parts[0] + '.' + parts[1].slice(0, 2);
        }

        // If starts with ".", change to "0."
        if (v.startsWith('.')) v = '0' + v;

        if (v !== input.value) input.value = v;
    });

    // Normalize on blur
    input.addEventListener('blur', () => {
        let v = input.value.trim();

        // Remove trailing dot: "12." -> "12"
        if (v.endsWith('.')) v = v.slice(0, -1);

        // Leading dot case handled already ("0.")
        input.value = v;
        updateTemplates();
    });
}

// -------- ADDITIONAL UPDATE FUNCTIONS ----- //
function createIdListeners() {
    const elements = [
        { id: ELEMENT_IDS.CASE_NUMBER, key: 'case_number', label: 'Case #:' },
        { id: ELEMENT_IDS.SR_NUMBER, key: 'sr_number', label: 'SR #:' },
        { id: ELEMENT_IDS.MIS_NUMBER, key: 'mis_number', label: 'MIS #:' }
    ];

    elements.forEach(e => e.input = document.getElementById(e.id));
    if (elements.some(e => !e.input)) {
        console.error(`Required elements not found: ${elements.map(e => e.id).join(', ')}`);
        return;
    }

    function updateIds() {
        elements.forEach(e => {
            const value = e.input.value.trim();
            formElementMapping[e.key] = value ? `#literal: ${e.label} ${value}` : '#literal:';
        });
        updateTemplates();
    }

    updateIds();

    elements.forEach(e => {
        e.input.addEventListener('input', updateIds);
    });
}

// Set letter date to current date if empty
// Set letter date for template only (do not modify the input element)
// Set letter date in the letter
function initLetterDate() {
    const letterDateId = formElementMapping.letter_date; // mapped ID
    const sendDateId = 'send-date';

    const letterDate = document.getElementById(letterDateId);
    const sendDate = document.getElementById(sendDateId);

    if (!letterDate || !sendDate) {
        console.error(`Required fields not found: ${letterDateId}, ${sendDateId}`);
        return;
    }

    function updateLetterDate() {
        const dateValue = letterDate.value ? letterDate.value.trim() : '';

        let formattedDate;
        const options = { year: 'numeric', month: 'long', day: 'numeric' }

        if (dateValue) {
            // If user entered date, use it
            const [year, month, day] = dateValue.split('-').map(Number);
            const dateObj = new Date(year, month - 1, day);
            formattedDate = dateObj.toLocaleDateString('en-CA', options);
        } else {
            // If empty, use current date
            const today = new Date();
            formattedDate = today.toLocaleDateString('en-CA', options);
        }

        sendDate.textContent = formattedDate;
    }

    updateLetterDate();
    letterDate.addEventListener('change', updateLetterDate);
}

// -------- TOGGLE BUTTON ----- //

/**
 * Initialize the letter toggle functionality
 */
let UI_STATE = { showLetter: false }; // persisted across re-renders

function initLetterToggle() {
    const { TOGGLE_BUTTON, LETTER_CONTAINER, FORM_CONTAINER } = ELEMENT_IDS;
    const toggleButton = document.getElementById(TOGGLE_BUTTON);
    const letterContent = document.getElementById(LETTER_CONTAINER);
    const formContainer = document.getElementById(FORM_CONTAINER);
    if (!toggleButton || !formContainer || !letterContent) {
        console.error(`Required elements not found: ${TOGGLE_BUTTON}, ${LETTER_CONTAINER}, ${FORM_CONTAINER}`);
        return;
    }

    function updateUI(showLetter) {
        debug(`Switching to ${showLetter ? 'letter' : 'form'} view`);
        letterContent.style.display = showLetter ? '' : 'none';
        formContainer.style.display = showLetter ? 'none' : '';
        toggleButton.textContent = showLetter ? UI_STRINGS.SHOW_FORM : UI_STRINGS.SHOW_LETTER;
    }

    // Initial state: show form, hide letter
    UI_STATE.showLetter = false;
    updateUI(UI_STATE.showLetter);

    toggleButton.addEventListener('click', function () {
        UI_STATE.showLetter = !UI_STATE.showLetter;
        updateUI(UI_STATE.showLetter);
    });
}

//-------- LIBRARY CODE - EXTEND, DO NOT EDIT ----------//

//------- Helper Functions -----//
function renderTextAreaParagraphs(output, val) {
    output.innerHTML = ""; // clear previous output

    // Split by newline variations: \r\n (Windows), \n (Unix), \r (old Mac)
    const lines = val.split(/\r?\n/);

    lines.forEach(line => {
        // Decide whether to skip empty lines or render them as blank paragraphs
        if (line.trim().length === 0) return; // skip empty lines; remove this line to keep blank <p>

        const p = document.createElement("p");
        p.textContent = line; // safe (escapes HTML)
        output.appendChild(p);
    });
}

//------- Moustache Template Functions -----//

//Uses Mustache v1.0
// Template data object that will be populated from form inputs
let templateData = {};

//Get nested object property using dot notation or array index
function getNestedProperty(obj, path) {
    return path.split('.').reduce((current, key) => {
        if (!current || typeof current !== 'object') return undefined;
        return Array.isArray(current) && !isNaN(key)
            ? current[Number(key)]
            : current[key];
    }, obj);
}

//Set nested object property using dot notation
function setNestedProperty(obj, path, value) {
    const keys = path.split(".");
    const lastKey = keys.pop();

    const target = keys.reduce((current, key, index) => {
        if (!current[key]) {
            // Check if next key is a number (array index)
            const nextKey = keys[index + 1];
            current[key] = !isNaN(nextKey) ? [] : {};
        }
        return current[key];
    }, obj);

    target[lastKey] = value;
}

//Get form value based on input type
function getFormValue(input) {
    const value = input.type === "checkbox"
        ? input.checked
        : input.type === "number"
            ? parseFloat(input.value) || 0
            : input.tagName === "TEXTAREA"
                ? input.value.split('\n').map(line => line.trim()).join('\n') + '\n'
                : input.value.trim();

    debug(`ID: ${input.id}, Type: ${input.type}, Value: ${value}`);
    return value;
}

//Collect all form data into templateData object using the mapping
function updateTemplateData() {
    templateData = {};

    // Iterate through the mapping object
    Object.entries(formElementMapping).forEach(([templateKey, elementId]) => {
        debug(`Template Key: ${templateKey}`);
        debug(`Element ID: ${elementId}`);

        // Check if templateKey is a literal value (starts with '#literal:')
        if (typeof elementId === "string" && elementId.startsWith("#literal:")) {
            const literalValue = elementId.slice(9); // Remove '#literal:' prefix
            debug(`Using literal value: ${literalValue}`);
            setNestedProperty(templateData, templateKey, literalValue);
        } else {
            // Standard element ID processing
            const element = document.getElementById(elementId);
            if (element) {
                const value = getFormValue(element);
                setNestedProperty(templateData, templateKey, value);
            } else {
                debug(`Element not found: ${elementId}`);
            }
        }
    });
}

//Process mustache templates
function processTemplates() {
    debug("processTemplates called - unified template processing");

    document.querySelectorAll(".moustache").forEach((el, i) => {
        if (!el.dataset.originalContent) {
            el.dataset.originalContent = el.textContent;
        }
        let content = el.dataset.originalContent;
        let val = "";

        content = content.replace(/\{\{([^}]+)\}\}/g, (m, key) => {
            key = key.trim();
            val = getNestedProperty(templateData, key);
            if (val !== undefined && val !== null && val !== "") {
                debug(`Replacing {{${key}}} with "${val}"`);
                return val;
            } else {
                debug(`No value for {{${key}}}, clearing`);
                return ""; // empty string if no value
            }
        });

        if (typeof val === "string" && val.includes("\n")) {
            renderTextAreaParagraphs(el, content);
        } else {
            el.textContent = content;
        }

        // Hide element if it's empty after replacement
        if (!el.textContent.trim()) {
            el.style.display = "none";
            debug(`Hiding moustache element #${i} (empty)`);
        } else {
            el.style.display = "";
            debug(`Showing moustache element #${i}`);
        }
    });
}

//Update templates when form data changes
function updateTemplates() {
    debug("Updating Templates");
    updateTemplateData();
    debug("Updated Template Data");
    debug("Processing Templates");
    processTemplates();
    debug("Processed Templates");
    //Deal with non moustache fields
    debug('Updating Non-Moustache Fields');
    updateNonMoustache();
    debug('Updated Non-Moustache Fields');
}

function addEventListeners() {
    Object.entries(formElementMapping).forEach(([templateKey, elementId]) => {
        debug("Processing element:", templateKey, "->", elementId);
        const element = document.getElementById(elementId);
        if (element) {
            debug("Element ID: " + element.id + " listener attached.");
            element.addEventListener("input", updateTemplates);
            element.addEventListener("change", updateTemplates); // For select and checkbox
            debug(`Added Event Listener to ${elementId}`);
        } else {
            debug(`Element not found: ${elementId}`);
        }
    });
}

// Initialize template system with multiple fallback methods
function initializeTemplateSystem() {
    debug("Initializing Template System");

    // Store original template content
    debug("Storing Original Template Content");
    const moustacheElements = document.querySelectorAll(".moustache");
    moustacheElements.forEach((element) => {
        element.dataset.originalContent = element.textContent;
    });
    debug(`Stored original template content for ${moustacheElements.length} elements`);

    // Add event listeners to form inputs
    debug("Adding Event Listeners to Form Inputs");
    addEventListeners();
    debug("Added Event Listeners to Form Inputs");

    // Initial template processing - runs AFTER date processing is set up
    debug("Running initial template processing");
    updateTemplates();
    debug("Template System Initialized");
}

// Enhanced production-ready bootstrapping - no reliance on DOM events
(function () {
    let globalInitialized = false;

    // More thorough element existence check
    function elementsExist() {
        const requiredElements = [".moustache"];

        return requiredElements.every((selector) => {
            const element = document.querySelector(selector);
            return element !== null && element.offsetParent !== null; // Check if visible
        });
    }

    // Force initialization without waiting for events
    function forceInitialize() {
        if (globalInitialized) return true;

        debug("Attempting force initialization...");

        if (!elementsExist()) {
            debug("Required elements not found or not visible yet...");
            return false;
        }

        try {
            debug("Elements found - initializing systems...");

            // Initialize template system
            initializeTemplateSystem();

            // Run additional initialization
            additionalInit();

            globalInitialized = true;
            debug("All systems initialized successfully!");
            return true;
        } catch (error) {
            debug("Initialization error: " + error.message);
            return false;
        }
    }

    // Immediate attempt
    if (forceInitialize()) return;

    // DOM ready fallback
    document.addEventListener("DOMContentLoaded", () => setTimeout(forceInitialize, 50));

    // MutationObserver for dynamic content
    if (window.MutationObserver && document.body) {
        const observer = new MutationObserver(mutations => {
            if (globalInitialized) {
                observer.disconnect();
                return;
            }

            if (mutations.some(m => m.type === "childList" && m.addedNodes.length > 0)) {
                setTimeout(forceInitialize, 25);
            }
        });

        observer.observe(document.body, { childList: true, subtree: true });
    }
})();

styles.content:
.letter-header {
    margin-bottom: 2em;
}

.header-row {
    display: flex;
    justify-content: space-between;
    width: 100%;
}

.header-row:not(:last-child) {
    margin-bottom: 1em;
}

.header-row-item {
    flex: 0 1 auto;
    /* Grow and shrink, starting at 50% */
    max-width: 50%;
    min-width: 0;
    /* Prevent overflow issues */
}

/* Use .left-align and .right-align classes to reorder two .header-row-item elements in the same .header-row without moving the HTML */
.header-row-item.left-align {
    order: 1;
}

.header-row-item.right-align {
    order: 2;
}

.letter-body p{
    margin-bottom: 0.75em;
}

#salutation {
    margin-bottom: 1.5em;
}

.contact-info {
    margin: 0 auto;
    border-collapse: collapse;
    table-layout: auto;
}

.contact-info th,
.contact-info td{
    padding: 6px 12px;
    vertical-align: top;
    text-align: left;
}

.signature {
    margin-top: 3em;
}

.text-info-field:has(.print-footer) {
    margin: 0 !important;
}

.footer-columns {
    display: flex;
    margin-top: 10px;
    flex-wrap: nowrap;
    gap: 10px;
}

.footer-columns .column {
    flex: 1;
    line-height: 1.3;
}

.horizontal-line {
    border-top: 1px solid #999;
    margin: 10px 0;
}

@media print {
    @page {
        size: letter;
        margin: 0.5in;
        /* Keep your page margins */
        margin-bottom: 28mm;
    }

    body {
        padding-bottom: 35mm !important;
    }

    #letter-content-961f5084-585e-4564-ae23-f18eebd455ff {
        display: block !important;
        margin-bottom: 0 !important;
        padding-bottom: 0 !important;
    }

    #form-b7a7577c-23da-4997-a8da-98060af183a7 {
        display: none !important;
    }
    
    .page-break {
        break-before: page !important;
    }

    .print-footer {
        position: fixed !important;
        bottom: 0 !important;
        height: 27mm !important;
        /* Keep your footer height */
        left: 0;
        right: 0;
        width: 100%;
    }
}
